import { execSync } from 'child_process';
import fs from 'fs';
const TOKG = process.env.GH_TOKEN;
function ghPut(p, buf, m) {
  const url = `https://api.github.com/repos/raimis079-creator/petshop-bridge/contents/${p}`;
  let sha=''; try { const j=JSON.parse(execSync(`curl -s -H "Authorization: Bearer ${TOKG}" "${url}"`).toString()); if(j.sha) sha=j.sha; } catch(e){}
  fs.writeFileSync('/tmp/p.json', JSON.stringify({ message: m, content: buf.toString('base64'), ...(sha?{sha}:{}) }));
  execSync(`curl -s -X PUT -H "Authorization: Bearer ${TOKG}" -d @/tmp/p.json "${url}"`, {maxBuffer:20*1024*1024});
}
function sh(c){ try { return execSync(c,{maxBuffer:30*1024*1024}).toString(); } catch(e){ return 'ERR'; } }
const AUTH = Buffer.from((process.env.WP_USER||'').trim()+':'+(process.env.WP_APP_PASS||'').replace(/\s+/g,'')).toString('base64');
const API = 'https://dev.avesa.lt/wp-json/code-snippets/v1/snippets';
const out = {};
// DVI PAKOPOS su atskirais atkurimo taskais (konsultanto #2):
//   pre-func   -> viskas kaip buvo
//   pre-visual -> funkcionalumas ijungtas, dizainas senas
const php = `
add_action('wp_loaded', function(){
	if ( ! isset(\$_GET['ps_s211']) ) { return; }
	\$m = sanitize_key(\$_GET['ps_s211']);
	\$core = WP_PLUGIN_DIR.'/petshop-core';
	\$fjs = \$core.'/assets/pet-form.js';
	\$css = \$core.'/assets/pet-form.css';
	\$prof = \$core.'/includes/class-pet-profile.php';
	\$ui = \$core.'/includes/class-pet-ui.php';
	\$o = array();
	if ( \$m === 'func' ) {
		foreach (array(\$fjs,\$prof) as \$f) if ( ! file_exists(\$f.'.bak-pre-func') ) copy(\$f, \$f.'.bak-pre-func');
		\$d1 = base64_decode(''); file_put_contents(\$fjs, \$d1);
		\$d2 = base64_decode('');   file_put_contents(\$prof, \$d2);
		\$o['pet-form.js'] = md5(\$d1)===md5_file(\$fjs) ? 'OK' : 'MISMATCH';
		\$o['class-pet-profile.php'] = md5(\$d2)===md5_file(\$prof) ? 'OK' : 'MISMATCH';
		// stulpeliu migracija
		if ( class_exists('Petshop_Pet_Profile') ) {
			\$r = new ReflectionMethod('Petshop_Pet_Profile','ensure_columns');
			\$r->setAccessible(true); \$r->invoke(null);
		}
		global \$wpdb;
		\$o['cols'] = array_values(array_intersect(
			\$wpdb->get_col("SHOW COLUMNS FROM {\$wpdb->prefix}ps_pets", 0),
			array('primary_product_sku','primary_product_name','primary_product_package')
		));
	} elseif ( \$m === 'visual' ) {
		foreach (array(\$fjs,\$css,\$ui) as \$f) if ( ! file_exists(\$f.'.bak-pre-visual') ) copy(\$f, \$f.'.bak-pre-visual');
		\$d1 = base64_decode(''); file_put_contents(\$fjs, \$d1);
		\$d2 = base64_decode('');    file_put_contents(\$css, \$d2);
		\$d3 = base64_decode('');     file_put_contents(\$ui, \$d3);
		\$o['pet-form.js'] = md5(\$d1)===md5_file(\$fjs) ? 'OK' : 'MISMATCH';
		\$o['pet-form.css'] = md5(\$d2)===md5_file(\$css) ? 'OK' : 'MISMATCH';
		\$o['class-pet-ui.php'] = md5(\$d3)===md5_file(\$ui) ? 'OK' : 'MISMATCH';
	} elseif ( \$m === 'rbvisual' ) {
		foreach (array(\$fjs,\$css,\$ui) as \$f) if ( file_exists(\$f.'.bak-pre-visual') ) { copy(\$f.'.bak-pre-visual', \$f); \$o['r'][] = basename(\$f); }
	} elseif ( \$m === 'rbfunc' ) {
		foreach (array(\$fjs,\$prof) as \$f) if ( file_exists(\$f.'.bak-pre-func') ) { copy(\$f.'.bak-pre-func', \$f); \$o['r'][] = basename(\$f); }
	}
	header('Content-Type: application/json'); echo wp_json_encode(\$o); exit;
});`;
fs.writeFileSync('/tmp/snip.json', JSON.stringify({ name:'TEMP M8 S211', code:php, scope:'global', active:true }));
sh(`curl -sk -X POST -H "Authorization: Basic ${AUTH}" -H "Content-Type: application/json" -d @/tmp/snip.json "${API}"`);
const f = sh('curl -sk --max-time 45 "https://dev.avesa.lt/?ps_s211=func"');
try { out.func = JSON.parse(f); } catch(e){ out.func_raw = f.slice(0,300); }
const v = sh('curl -sk --max-time 45 "https://dev.avesa.lt/?ps_s211=visual"');
try { out.visual = JSON.parse(v); } catch(e){ out.visual_raw = v.slice(0,300); }
out.home = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/"');
out.acct = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/my-account/"');
out.rest = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/wp-json/petshop/v1"');
out.anketa = sh('curl -sk -o /dev/null -w "%{http_code}" --max-time 25 "https://dev.avesa.lt/anketa-testas/"');
if (out.home!=='200'||out.acct!=='200'||out.rest!=='200'||out.anketa!=='200') {
  out.ROLLBACK = sh('curl -sk "https://dev.avesa.lt/?ps_s211=rbvisual"').slice(0,200);
}
const kphp = `add_action('wp_loaded', function(){ if(!isset(\$_GET['ps_k7'])||\$_GET['ps_k7']!=='Rr3Ww8Yy'){return;} global \$wpdb; \$n=\$wpdb->query("DELETE FROM {\$wpdb->prefix}snippets WHERE name LIKE 'TEMP M8%'"); echo wp_json_encode(array('d'=>\$n)); exit; });`;
fs.writeFileSync('/tmp/k.json', JSON.stringify({ name:'TEMP M8 Kill w7', code:kphp, scope:'global', active:true }));
sh(`curl -sk -X POST -H "Authorization: Basic ${AUTH}" -H "Content-Type: application/json" -d @/tmp/k.json "${API}"`);
sh('curl -sk --max-time 25 "https://dev.avesa.lt/?ps_k7=Rr3Ww8Yy"');
ghPut('screenshots/m8_s211.json', Buffer.from(JSON.stringify(out)), 's211 deploy');
console.log('DONE');
